import Container from 'react-bootstrap/Container';
import Row from 'react-bootstrap/Row';
import Col from 'react-bootstrap/Col';
import variant from 'react-bootstrap/esm/ThemeProvider';

function AutoLayoutExample() {
  return (
    <Container style={{ height: '100vh' }} id='Container'>
      <Row  style={{ height: '33%' }}>
        <Col style={{ textAlign: 'center' },{border: '1px solid #ccc'}} className='bg-success border-danger border-3 p-3'>1 of 3</Col>
        <Col style={{ textAlign: 'center' },{border: '1px solid #ccc'}} className='bg-warning'>2 of 3</Col>
        <Col style={{ textAlign: 'center' },{border: '1px solid #ccc'}} className='bg-danger'>3 of 3</Col>

      </Row>
      <Row style={{ height: '33%' }}>
        <Col style={{ textAlign: 'center' },{border: '1px solid #ccc'}} className='bg-info'>1 of 1</Col>
      </Row>
      <Row style={{ height: '33%' }} >
        <Col style={{ textAlign: 'center' },{border: '1px solid #ccc'}} className='bg-primary'>1 of 2</Col>
        <Col style={{ textAlign: 'center' },{border: '1px solid #ccc'}} className='bg-secondary'>2 of 2</Col>
      </Row>
    </Container>
  );
}

export default AutoLayoutExample;
